import sysfrom pathlib import Pathimport jsonimport numpy as npimport pandas as pdfrom sklearn.metrics import accuracy_score, f1_score# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import PROCESSED_DATA_DIR, REPORTS_DIRDATASET_TAG = "large_lite"LABEL_COL = "label_5d"def load_data():    train_df = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d_large_lite.parquet")    test_df = pd.read_parquet(PROCESSED_DATA_DIR / "test_doc_5d_large_lite.parquet")    return train_df, test_dfdef main():    train_df, test_df = load_data()    y_train = train_df[LABEL_COL].values    y_test = test_df[LABEL_COL].values    # Estimate class probability from training data    p_pos = np.mean(y_train)    print(f"Estimated P(y=1) from train: {p_pos:.4f}")    # Random prediction based on this probability    np.random.seed(42)    y_pred = np.random.binomial(1, p_pos, size=len(y_test))    acc = accuracy_score(y_test, y_pred)    f1 = f1_score(y_test, y_pred)    print("\n=== RANDOM BASELINE (STRATIFIED) ===")    print(f"Test Accuracy: {acc:.4f}")    print(f"Test F1:       {f1:.4f}")    # Save results    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    out_path = REPORTS_DIR / f"random_baseline_{DATASET_TAG}.json"    with open(out_path, "w") as f:        json.dump({            "p_positive": float(p_pos),            "test_accuracy": acc,            "test_f1": f1        }, f, indent=2)    print("\nSaved to:", out_path)if __name__ == "__main__":    main()